import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { SupplierAuthService } from '../../../services/supplier-auth.service';
import { SupplierProductsService, SupplierProduct } from '../../../services/supplier-products.service';
import { UnitService, Unit } from '../../../services/Piatti/unit.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-supplier-ingredients',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, LucideAngularModule],
  templateUrl: './supplier-ingredients.html',
  styleUrls: ['./supplier-ingredients.css']
})
export class SupplierIngredients implements OnInit {
  private supplierAuthService = inject(SupplierAuthService);
  private supplierProductsService = inject(SupplierProductsService);
  private unitService = inject(UnitService);
  private fb = inject(FormBuilder);
  private router = inject(Router);

  // Dati principali
  products: SupplierProduct[] = [];
  units: Unit[] = [];
  filteredProducts: SupplierProduct[] = [];
  
  // Stato UI
  showProductForm = false;
  isEditing = false;
  currentProductId: string | null = null;
  searchTerm = '';
  isLoading = true;

  // Filtri
  showAvailableOnly = false;
  sortBy: 'name' | 'price' = 'name';

  // Form
  productForm: FormGroup;

  // Statistiche
  get availableProductsCount(): number {
    return this.products.filter(p => p.is_available).length;
  }

  get totalProductsValue(): number {
    return this.products.reduce((sum, product) => sum + product.unit_price, 0);
  }

  constructor() {
    this.productForm = this.fb.group({
      product_name: ['', [Validators.required, Validators.minLength(2)]],
      description: [''],
      unit_price: [0, [Validators.required, Validators.min(0)]],
      package_quantity: [1, [Validators.required, Validators.min(0.001)]],
      unit_id: [''],
      is_available: [true]
    });
  }

  async ngOnInit() {
    await this.loadData();
  }

  async loadData() {
    this.isLoading = true;
    
    try {
      // Carica unità di misura
      this.unitService.units$.subscribe(units => {
        this.units = units;
      });

      // Carica prodotti fornitore
      await this.supplierProductsService.loadSupplierProducts();
      this.supplierProductsService.products$.subscribe(products => {
        this.products = products;
        this.applyFilters();
        this.isLoading = false;
      });

    } catch (error) {
      console.error('Error loading data:', error);
      this.isLoading = false;
    }
  }

  applyFilters() {
    let filtered = this.products;

    // Filtro per ricerca
    if (this.searchTerm) {
      filtered = filtered.filter(product =>
        product.product_name.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        product.description?.toLowerCase().includes(this.searchTerm.toLowerCase())
      );
    }

    // Filtro per disponibilità
    if (this.showAvailableOnly) {
      filtered = filtered.filter(product => product.is_available);
    }

    // Ordinamento
    filtered = [...filtered].sort((a, b) => {
      switch (this.sortBy) {
        case 'name':
          return a.product_name.localeCompare(b.product_name);
        case 'price':
          return a.unit_price - b.unit_price;
        default:
          return 0;
      }
    });

    this.filteredProducts = filtered;
  }

  onSearchChange(searchTerm: string) {
    this.searchTerm = searchTerm;
    this.applyFilters();
  }

  toggleAvailableFilter() {
    this.showAvailableOnly = !this.showAvailableOnly;
    this.applyFilters();
  }

  onSortChange(sortBy: 'name' | 'price') {
    this.sortBy = sortBy;
    this.applyFilters();
  }

  async onSubmit() {
    if (this.productForm.invalid) {
      this.markFormGroupTouched();
      return;
    }

    try {
      if (this.isEditing && this.currentProductId) {
        const success = await this.supplierProductsService.updateProduct(this.currentProductId, this.productForm.value);
        if (success) {
          console.log('Prodotto aggiornato con successo');
          this.resetForm();
        }
      } else {
        const product = await this.supplierProductsService.createProduct(this.productForm.value);
        if (product) {
          console.log('Prodotto creato con successo');
          this.resetForm();
        }
      }
    } catch (error) {
      console.error('Errore durante il salvataggio:', error);
    }
  }

  editProduct(product: SupplierProduct) {
    this.isEditing = true;
    this.currentProductId = product.id;
    this.productForm.patchValue({
      product_name: product.product_name,
      description: product.description || '',
      unit_price: product.unit_price,
      package_quantity: product.package_quantity,
      unit_id: product.unit_id || '',
      is_available: product.is_available
    });
    this.showProductForm = true;
  }

  async deleteProduct(id: string) {
    if (confirm('Sei sicuro di voler eliminare questo prodotto?')) {
      const success = await this.supplierProductsService.deleteProduct(id);
      if (success) {
        console.log('Prodotto eliminato');
      }
    }
  }

  newProduct() {
    this.resetForm();
    this.showProductForm = true;
    this.isEditing = false;
  }

  resetForm() {
    this.productForm.reset({
      product_name: '',
      description: '',
      unit_price: 0,
      package_quantity: 1,
      unit_id: '',
      is_available: true
    });
    this.isEditing = false;
    this.currentProductId = null;
    this.showProductForm = false;
  }

  // Metodi helper
  getUnitSymbol(unitId: string | undefined): string {
    if (!unitId) return '';
    const unit = this.units.find(u => u.id === unitId);
    return unit ? unit.symbol : '';
  }

  getProductStatus(product: SupplierProduct): { class: string, text: string } {
    if (product.is_available) {
      return { class: 'active', text: 'Disponibile' };
    } else {
      return { class: 'inactive', text: 'Non disponibile' };
    }
  }

  getUnitsByType(type: 'weight' | 'volume' | 'piece'): Unit[] {
    return this.units.filter(unit => unit.type === type);
  }

  private markFormGroupTouched() {
    Object.keys(this.productForm.controls).forEach(key => {
      const control = this.productForm.get(key);
      control?.markAsTouched();
    });
  }

  // Getters per il template
  get product_name() { return this.productForm.get('product_name'); }
  get unit_price() { return this.productForm.get('unit_price'); }
  get package_quantity() { return this.productForm.get('package_quantity'); }
}